import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as t}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as l,o as i,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"en/Safety/cloudflare-api-token.md","filePath":"en/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),r={name:"en/Safety/cloudflare-api-token.md"};function s(d,e,h,c,p,u){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials allow ImgBed to purge Cloudflare CDN cache after files change.</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open the admin panel, then go to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>You need to fill in:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="what-this-setting-does" tabindex="-1">What This Setting Does <a class="header-anchor" href="#what-this-setting-does" aria-label="Permalink to &quot;What This Setting Does&quot;">​</a></h2><p>Cloudflare may cache public image URLs.</p><p>Caching makes image delivery faster, but it can also leave stale content visible for a while after you delete, block, replace, or move a file.</p><p>After Cloudflare API credentials are configured, ImgBed attempts to purge the related Cloudflare cache when those operations finish.</p><p>This is useful when:</p><ul><li>You delete an image and want the public link to stop working as soon as possible.</li><li>You block an image and want visitors to stop seeing the original file.</li><li>You replace a file with the same name and want visitors to see the new version sooner.</li><li>You move or rename files and want old path cache to refresh quickly.</li><li>You change public access rules and want public gallery or random image cache to update sooner.</li></ul><h2 id="what-happens-if-you-leave-it-empty" tabindex="-1">What Happens If You Leave It Empty <a class="header-anchor" href="#what-happens-if-you-leave-it-empty" aria-label="Permalink to &quot;What Happens If You Leave It Empty&quot;">​</a></h2><p>ImgBed still works normally without this setting.</p><p>The only difference is that ImgBed will not actively purge Cloudflare CDN cache. Visitors may continue to see old content until the Cloudflare cache expires naturally.</p><h2 id="how-to-find-the-zone-id" tabindex="-1">How To Find the Zone ID <a class="header-anchor" href="#how-to-find-the-zone-id" aria-label="Permalink to &quot;How To Find the Zone ID&quot;">​</a></h2><p>The Zone ID is the Cloudflare Zone ID of the site used by your ImgBed domain.</p><ol><li>Sign in to the Cloudflare dashboard.</li><li>Open the site that contains your ImgBed domain.</li><li>Find <code>Zone ID</code> on the site overview page.</li><li>Copy it into the <code>Zone ID</code> field in ImgBed.</li></ol><p>This is the site Zone ID, not the account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Enter the email address you use to sign in to Cloudflare.</p><p>It must match the API Key you provide below.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Enter your Cloudflare Global API Key.</p><ol><li>Sign in to the Cloudflare dashboard.</li><li>Open your profile.</li><li>Go to the API Tokens page.</li><li>Find <code>Global API Key</code>.</li><li>View and copy it.</li><li>Paste it into the <code>API Key</code> field in ImgBed.</li></ol><p><img src="'+t+'" alt="View global API key" loading="lazy"></p><h2 id="when-it-takes-effect" tabindex="-1">When It Takes Effect <a class="header-anchor" href="#when-it-takes-effect" aria-label="Permalink to &quot;When It Takes Effect&quot;">​</a></h2><p>After filling in the fields, save the settings.</p><p>Future file changes will automatically attempt to purge Cloudflare cache. Past operations are not retroactively purged. If you deleted or replaced a file before setting this up, wait for Cloudflare cache to expire or purge it manually in Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="is-this-required" tabindex="-1">Is This Required? <a class="header-anchor" href="#is-this-required" aria-label="Permalink to &quot;Is This Required?&quot;">​</a></h3><p>No.</p><p>If your domain does not use Cloudflare, or you do not mind CDN cache delay, you can leave it empty.</p><h3 id="will-wrong-credentials-break-uploads" tabindex="-1">Will Wrong Credentials Break Uploads? <a class="header-anchor" href="#will-wrong-credentials-break-uploads" aria-label="Permalink to &quot;Will Wrong Credentials Break Uploads?&quot;">​</a></h3><p>Usually no.</p><p>Wrong credentials only prevent ImgBed from purging Cloudflare cache. Upload and normal file access should continue to work.</p><h3 id="why-can-a-deleted-image-still-be-opened" tabindex="-1">Why Can a Deleted Image Still Be Opened? <a class="header-anchor" href="#why-can-a-deleted-image-still-be-opened" aria-label="Permalink to &quot;Why Can a Deleted Image Still Be Opened?&quot;">​</a></h3><p>The most common reason is that Cloudflare still has the old file cached.</p><p>With correct Cloudflare API credentials, ImgBed purges the related URL cache when a file is deleted.</p><h3 id="why-do-i-still-see-the-old-image-after-replacing-a-file" tabindex="-1">Why Do I Still See the Old Image After Replacing a File? <a class="header-anchor" href="#why-do-i-still-see-the-old-image-after-replacing-a-file" aria-label="Permalink to &quot;Why Do I Still See the Old Image After Replacing a File?&quot;">​</a></h3><p>This is also usually caused by CDN cache.</p><p>After this setting is configured, ImgBed attempts to purge the old URL cache when a file with the same name is overwritten.</p>',44)])])}const I=l(r,[["render",s]]);export{y as __pageData,I as default};
